(async () => {
  if (!window._blobs) window._blobs = {};
  const files = {"programmatic-seo.js": "", "pub-quiz-generator.html": "", "quality-engine.js": "", "queue-processor.js": "", "railway-services.json": "", "railway.json": "ewogICIkc2NoZW1hIjogImh0dHBzOi8vcmFpbHdheS5hcHAvcmFpbHdheS5zY2hlbWEuanNvbiIsCiAgImJ1aWxkIjogewogICAgImJ1aWxkZXIiOiAiTklYUEFDS1MiCiAgfSwKICAiZGVwbG95IjogewogICAgInJlc3RhcnRQb2xpY3lUeXBlIjogIk9OX0ZBSUxVUkUiLAogICAgInJlc3RhcnRQb2xpY3lNYXhSZXRyaWVzIjogMTAKICB9Cn0K", "railway.toml": "", "recommendations-engine.js": "", "reddit-bot.js": "", "referee-db.html": "", "referee-intelligence.js": "", "requirements.txt": "cHl0aG9uLXRlbGVncmFtLWJvdD09MjEuNQpodHRweD09MC4yNy4wCg=="};
  const results = await Promise.all(Object.entries(files).map(async ([path, content]) => {
    const r = await fetch('https://api.github.com/repos/' + window._owner + '/' + window._repo + '/git/blobs', {
      method: 'POST',
      headers: {'Authorization': 'token ' + window._token, 'Content-Type': 'application/json', 'Accept': 'application/vnd.github.v3+json'},
      body: JSON.stringify({content, encoding: 'base64'})
    });
    const d = await r.json();
    if (d.sha) {
      window._blobs[path] = d.sha;
      return 'OK:' + path;
    } else {
      return 'ERR:' + path + ':' + JSON.stringify(d).substring(0,80);
    }
  }));
  return 'Batch 21/30 done. Files: ' + Object.keys(window._blobs).length + ' | ' + results.filter(r=>r.startsWith('ERR')).join(' ');
})();